import React, {useState} from "react";
import {Heart} from "lucide-react";
import ParamCard from "./Tools/ParamCard";
import ParamHeader from "./Tools/ParamHeader";

function DoubleClickSelector({
    value = null,
    onChange,
    iconName = 'Star',
    colorIndex = 5,
    onIconClick
}) {
    const [pendingMood, setPendingMood] = useState(null);

    const moods = [
        { value: 1, emoji: '😊', label: '开心' },
        { value: 2, emoji: '😍', label: '爱恋' },
        { value: 3, emoji: '🥰', label: '甜蜜' },
        { value: 4, emoji: '✨', label: '兴奋' },
        { value: 5, emoji: '💖', label: '幸福' }
    ];

    const handleMoodClick = (moodValue) => {
        if (pendingMood === moodValue) {
            onChange(moodValue);
            setPendingMood(null);
        } else {
            setPendingMood(moodValue);
            if (value !== moodValue) {
                onChange(null);
            }
        }
    };

    return (
        <ParamCard>
            <div className="flex items-center justify-between mb-3">
                <ParamHeader
                    label="心情状态"
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
                {pendingMood && (
                    <span className="text-xs text-pink-500 font-semibold animate-pulse">
                        再点一次确认 ♡
                    </span>
                )}
            </div>
            <div className="flex gap-2">
                {moods.map((mood) => {
                    const isPending = pendingMood === mood.value;
                    const isSelected = value === mood.value;

                    return (
                        <button
                            key={mood.value}
                            onClick={() => handleMoodClick(mood.value)}
                            className={`relative flex-1 py-3 rounded-xl font-bold transition-all ${
                                isSelected
                                    ? 'bg-gradient-to-r from-pink-500 to-rose-500 text-white shadow-xl scale-110 ring-4 ring-pink-300'
                                    : isPending
                                        ? 'bg-gradient-to-r from-pink-300 to-rose-300 text-white shadow-lg scale-105 ring-2 ring-pink-400 animate-pulse'
                                        : 'bg-white/80 text-gray-600 hover:bg-white hover:scale-105'
                            }`}
                        >
                            <div className="flex flex-col items-center gap-1">
                                <span className="text-lg">{mood.emoji}</span>
                                <span className="text-xs">{mood.label}</span>
                            </div>
                            {isPending && (
                                <div className="absolute -top-1 -right-1 w-3 h-3 bg-pink-500 rounded-full animate-ping" />
                            )}
                            {isSelected && (
                                <div className="absolute -top-1 -right-1">
                                    <Heart className="text-white fill-white" size={12} />
                                </div>
                            )}
                        </button>
                    );
                })}
            </div>
        </ParamCard>
    );
}

export default DoubleClickSelector
